        </span>
        <span class="logo-text">
          <strong>PEEPAL GLOBAL</strong>
          <small>EXPORT IMPORT</small>
        </span>
      </a>
    </div>
    <ul class="nav-links">
      <li><a routerLink="/" routerLinkActive="active" [routerLinkActiveOptions]="{ exact: true }">Home</a></li>
      <li><a routerLink="/about" routerLinkActive="active">About Us</a></li>
      <li><a routerLink="/products" routerLinkActive="active">Industries</a></li>
      <li><a routerLink="/contact" routerLinkActive="active">Contact Us</a></li>
      <li><a routerLink="/admin" routerLinkActive="active">Admin</a></li>
      <li><a routerLink="/quote" routerLinkActive="active" class="btn-quote">Request a Quote</a></li>
    </ul>
  </div>
</nav>

<router-outlet></router-outlet>

<footer class="footer">
  <div class="container">
    <p>&copy; 2026 Peepal Export. All rights reserved.</p>
  </div>
</footer>
